import{_ as l,o as a,c as i,ag as r}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"レポート","description":"","frontmatter":{"title":"レポート"},"headers":[],"relativePath":"tenant/13-reports.md","filePath":"tenant/13-reports.md"}'),d={name:"tenant/13-reports.md"};function e(o,t,h,n,p,s){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="_13-レポート" tabindex="-1">13. レポート <a class="header-anchor" href="#_13-レポート" aria-label="Permalink to &quot;13. レポート&quot;">​</a></h1><p>レポートでは、売上、会計、商品、客席、スタッフ、在庫、予約、満足度、カート離脱などの状況を確認できます。日々の振り返り、問い合わせ対応、月次改善に使います。</p><h2 id="主なレポート" tabindex="-1">主なレポート <a class="header-anchor" href="#主なレポート" aria-label="Permalink to &quot;主なレポート&quot;">​</a></h2><table tabindex="0"><thead><tr><th>レポート</th><th>確認できること</th></tr></thead><tbody><tr><td>週次サマリー</td><td>直近1週間の売上、客数、客単価、前週比、人気商品Top3</td></tr><tr><td>売上レポート</td><td>日別、時間帯別の売上と客数</td></tr><tr><td>売上ドリルダウン</td><td>日別 → 商品 → 注文 → 会計履歴までの追跡</td></tr><tr><td>レジ分析</td><td>現金、入金、出金、差額、外部決済控え、返金、締め前チェック</td></tr><tr><td>注文履歴</td><td>過去注文、注文内容、取消、問い合わせ時の確認</td></tr><tr><td>回転率・客層分析</td><td>テーブル回転、滞在時間、調理時間、人数傾向</td></tr><tr><td>スタッフ評価・監査</td><td>勤怠、担当別実績、操作履歴、打刻精度</td></tr><tr><td>満足度分析</td><td>評価件数、平均評価、低評価の理由・品目・時間帯</td></tr><tr><td>併売分析</td><td>一緒に注文されやすい品目の組み合わせ</td></tr><tr><td>カート離脱・キャンセル分析</td><td>カートに入れた後で外された商品、注文内キャンセル</td></tr><tr><td>緊急会計台帳</td><td>緊急レジで記録した会計の確認</td></tr><tr><td>予約レポート</td><td>予約件数、来店数、キャンセル、no-show、時間帯傾向</td></tr></tbody></table><h2 id="週次サマリー" tabindex="-1">週次サマリー <a class="header-anchor" href="#週次サマリー" aria-label="Permalink to &quot;週次サマリー&quot;">​</a></h2><p>売上レポートの先頭には、直近7日間の週次サマリーが表示されます。</p><p>確認できる項目:</p><ul><li>売上合計</li><li>客数</li><li>客単価</li><li>前週比</li><li>人気商品Top3</li></ul><p>週次サマリーは、日々の細かい伝票確認ではなく、店長が「今週の流れが良いか悪いか」を早く見るためのものです。詳細な注文や会計は、注文履歴、レジ分析、売上ドリルダウンで確認してください。</p><h2 id="売上ドリルダウン" tabindex="-1">売上ドリルダウン <a class="header-anchor" href="#売上ドリルダウン" aria-label="Permalink to &quot;売上ドリルダウン&quot;">​</a></h2><p>管理画面の <strong>運営管理 → 売上ドリル</strong> では、売上を次の順で追跡できます。</p><ol><li>期間内の日別売上</li><li>指定日の商品別売上</li><li>指定商品を含む注文一覧</li><li>注文詳細と会計履歴</li></ol><p>使いどころ:</p><ul><li>「この商品の売上がなぜ伸びたか」を注文単位で確認する</li><li>問い合わせ時に、注文IDから会計履歴まで確認する</li><li>返金や取消の可能性がある注文を、レジ分析と突き合わせる</li><li>人気商品や売上上位商品の提供時間・時間帯を確認する</li></ul><p>売上ドリルで表示される商品別売上は、注文内の品目情報から集計します。会計済み注文を中心に見るため、未会計や取消が混ざる場合は注文履歴・レジ分析も確認してください。</p><h2 id="満足度分析" tabindex="-1">満足度分析 <a class="header-anchor" href="#満足度分析" aria-label="Permalink to &quot;満足度分析&quot;">​</a></h2><p>管理画面 → レポート → 満足度分析 から開きます。お客様のセルフ注文画面で送信された評価（1〜5）を集計し、店舗改善に活用できます。</p><ul><li><strong>サマリー</strong>: 評価件数、平均評価、低評価件数（1〜2）、低評価率、高評価件数（4〜5）</li><li><strong>低評価の理由ランキング</strong>: 提供が遅かった／味／温度／量／注文内容の相違／接客／清潔感／価格／その他</li><li><strong>低評価が出た品目ランキング</strong>: どの品目に低評価が集中しているか</li><li><strong>時間帯別 低評価</strong>: ピーク時に提供品質が落ちていないか確認</li><li><strong>直近の低評価一覧</strong>: 日時・品目・評価・理由・自由コメント・テーブル・注文ID</li></ul><div class="tip custom-block"><p class="custom-block-title">低評価は改善のヒントとして活用してください</p><p>低評価はスタッフ個人の責任ではなく、「品目・時間帯・店舗運営の改善点」として活用する前提で設計しています。顧客セルフ注文ではスタッフ担当者が特定されないケースも多いため、まずは品目・時間帯・オペレーションの見直しをお勧めします。</p></div><p>オーナー画面の「全店舗横断レポート」にも、全店舗合算の満足度サマリー・店舗別平均評価・低評価が多い品目・理由ランキングが表示されます。</p><h2 id="カート離脱・キャンセル分析" tabindex="-1">カート離脱・キャンセル分析 <a class="header-anchor" href="#カート離脱・キャンセル分析" aria-label="Permalink to &quot;カート離脱・キャンセル分析&quot;">​</a></h2><p>管理画面の <strong>運営管理 → カート離脱</strong> では、お客様がカートへ入れた後に外した商品を確認できます。注文履歴に残る注文内キャンセルも、記録がある環境では同じ画面に表示されます。</p><p>確認できる項目:</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>カート投入</td><td>対象期間に商品がカートへ入った回数</td></tr><tr><td>カート削除</td><td>カートから外された回数</td></tr><tr><td>削除率</td><td>カート投入に対する削除割合</td></tr><tr><td>最終</td><td>最後に投入または削除された時刻</td></tr><tr><td>注文内キャンセル</td><td>注文後に外された商品、数量、注文ID</td></tr></tbody></table><p>削除率が高い商品は、次を確認してください。</p><ul><li>写真が実物と合っているか</li><li>価格が分かりにくくないか</li><li>必須オプションが複雑すぎないか</li><li>説明文やアレルゲンが不足していないか</li><li>売り切れや代替提案の表示が適切か</li></ul><p>カート離脱は「売れなかった理由」を断定するものではありません。改善候補を見つけるための参考データとして使います。</p><h2 id="レジ分析" tabindex="-1">レジ分析 <a class="header-anchor" href="#レジ分析" aria-label="Permalink to &quot;レジ分析&quot;">​</a></h2><p>レジ分析では、閉店時の現金差額や外部決済控えを確認します。</p><p>主な確認項目:</p><ul><li>開局金額、入金、出金、締め金額</li><li>過不足額</li><li>支払い方法別売上</li><li>外部カード、外部QR、その他外部決済の控え番号</li><li>返金、取消、領収書再発行</li><li>閉店引き継ぎメモ</li></ul><p>カード決済やQR決済は、POSLAが決済そのものを実行するのではなく、店舗が契約している外部端末の完了結果を記録します。差額や問い合わせがある場合は、外部端末の控えとPOSLAの会計記録を突き合わせてください。</p><h2 id="注文履歴" tabindex="-1">注文履歴 <a class="header-anchor" href="#注文履歴" aria-label="Permalink to &quot;注文履歴&quot;">​</a></h2><p>注文履歴は、過去注文の検索と問い合わせ対応に使います。</p><p>見るポイント:</p><ul><li>注文ID</li><li>注文日時</li><li>テーブル、注文者情報</li><li>注文内容、数量、金額</li><li>注文ステータス</li><li>取消や返金に関係するメモ</li></ul><p>お客様から「何を頼んだか」「会計済みか」「キャンセルしたか」を聞かれた場合は、注文履歴とレジ分析を合わせて確認します。</p><h2 id="回転率・客層分析" tabindex="-1">回転率・客層分析 <a class="header-anchor" href="#回転率・客層分析" aria-label="Permalink to &quot;回転率・客層分析&quot;">​</a></h2><p>回転率・客層分析では、テーブルの滞在時間、回転数、人数傾向、調理時間を確認します。</p><p>活用例:</p><ul><li>予約枠の標準滞在時間を見直す</li><li>ピーク時間のシフト人数を見直す</li><li>提供が遅れやすい時間帯を見つける</li><li>テーブル配置や席種を見直す</li></ul><p>回転率は、テーブル開放、着席、会計、退店処理が正しく行われているほど精度が上がります。ハンディやレジでセッション終了を忘れると、滞在時間が長く見えることがあります。</p><h2 id="スタッフ評価・監査" tabindex="-1">スタッフ評価・監査 <a class="header-anchor" href="#スタッフ評価・監査" aria-label="Permalink to &quot;スタッフ評価・監査&quot;">​</a></h2><p>スタッフ評価・監査では、スタッフごとの操作や勤怠に関係する情報を確認します。</p><p>確認できる内容:</p><ul><li>担当した注文数や操作履歴</li><li>打刻の有無、遅刻、早退、残業</li><li>交代/欠勤申請や承認記録</li><li>監査ログに残る重要操作</li></ul><p>スタッフ評価は、共有アカウントでは正しく集計できません。POSLAでは、全スタッフが個別アカウントでログインする運用を前提にしています。</p><h2 id="併売分析" tabindex="-1">併売分析 <a class="header-anchor" href="#併売分析" aria-label="Permalink to &quot;併売分析&quot;">​</a></h2><p>併売分析では、一緒に注文されやすい品目の組み合わせを確認します。</p><p>活用例:</p><ul><li>セットメニューを作る</li><li>おすすめ表示を見直す</li><li>ドリンクやサイドメニューの提案を強化する</li><li>KDSの提供順や仕込み量を調整する</li></ul><p>併売は、単品の売上だけでは見えない組み合わせを見るための参考です。期間や曜日によって傾向が変わるため、ランチ、ディナー、週末などに分けて見ると判断しやすくなります。</p><h2 id="期間の選び方" tabindex="-1">期間の選び方 <a class="header-anchor" href="#期間の選び方" aria-label="Permalink to &quot;期間の選び方&quot;">​</a></h2><p>日報は営業終了後、週報は週明け、月報は月末または翌月初に確認する運用を推奨します。深夜営業の店舗では、営業日区切り時刻に注意してください。</p><p>深夜営業の店舗では、店舗設定の「営業日区切り時刻」により、暦日と営業日の集計が異なる場合があります。売上が想定と違う場合は、期間だけでなく営業日区切りも確認してください。</p><h2 id="csv出力" tabindex="-1">CSV出力 <a class="header-anchor" href="#csv出力" aria-label="Permalink to &quot;CSV出力&quot;">​</a></h2><p>必要に応じてCSVを出力し、会計ソフトや表計算ソフトで集計できます。出力後は個人情報や売上情報の取り扱いに注意してください。</p><h2 id="活用例" tabindex="-1">活用例 <a class="header-anchor" href="#活用例" aria-label="Permalink to &quot;活用例&quot;">​</a></h2><ul><li>売れ筋商品を確認して仕入れ量を調整する</li><li>回転率の低い時間帯を見つけて人員配置を見直す</li><li>返金やレジ差額を確認して運用改善につなげる</li><li>スタッフ別の実績を評価や教育に活用する</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>数値が合わない</td><td>期間、営業日区切り、会計済み状態を確認してください。</td></tr><tr><td>CSVが開けない</td><td>UTF-8対応のソフトで開いてください。</td></tr><tr><td>特定店舗が出ない</td><td>店舗選択と閲覧権限を確認してください。</td></tr><tr><td>レジ差額がある</td><td>入金、出金、返金、現金残高を確認してください。</td></tr><tr><td>商品別売上が注文履歴と違う</td><td>会計済み注文、取消、返金、対象期間、営業日区切りを確認してください。</td></tr><tr><td>カート離脱が多い</td><td>写真、価格、説明、必須オプション、売り切れ表示を確認してください。</td></tr></tbody></table>',61)])])}const b=l(d,[["render",e]]);export{c as __pageData,b as default};
